sysrule_assignment.script:
/**
 * Intelligent Consumer Case Routing Script
 *
 * Evaluates the following criteria to determine the correct assignment group:
 * 1. Complaint Category (billing, delivery, product quality, customer service)
 * 2. Product Category (electronics, clothing, food, home & garden)
 * 3. Store Location (retail_store reference)
 * 4. Region (from store's region field: north, south, east, west, central)
 * 5. Priority (1=Critical, 2=High, 3=Moderate, 4=Low)
 * 6. Severity/Escalation Level (none, tier_1, tier_2, tier_3, management)
 *
 * Routing Decision Matrix:
 * - Quality Team: Critical priority product issues, safety concerns, high-severity defects
 * - Regional Support: Escalated cases (tier_2+), high-priority regional issues
 * - Refund Team: Billing & Pricing complaints, overcharge disputes
 * - Logistics: Delivery Issues, late delivery, shipping problems
 * - Store Support: In-store complaints, customer service, staff behavior issues
 * - Warehouse: Moderate/low priority product quality, returns requiring inspection
 * - Customer Care: Default catch-all for unmatched cases
 */

// Gather routing criteria
var complaintCategory = current.complaint_category.getDisplayValue() || '';
var productCategory = current.product_category.getDisplayValue() || '';
var productDepartment = '';
var storeRegion = '';
var storeType = '';
var priority = parseInt(current.priority) || 4;
var escalationLevel = current.escalation_level + '';
var channel = current.channel + '';

// Dot-walk through references to get classification data
if (!current.retail_store.nil()) {
    storeRegion = current.retail_store.region + '';
    storeType = current.retail_store.store_type + '';
}

if (!current.product_category.nil()) {
    productDepartment = current.product_category.department + '';
}

// Track whether assignment was made
var assigned = false;

// ===========================
// RULE 1: Critical Priority + Product Issues → Quality Team
// Immediate quality/safety response for critical defects
// ===========================
if (!assigned && priority == 1 &&
    (complaintCategory == 'Product Quality' ||
     complaintCategory == 'Defective Product')) {
    current.assignment_group.setDisplayValue('Quality Team');
    assigned = true;
}

// ===========================
// RULE 2: High Escalation (Tier 2+) → Regional Support
// Escalated cases need regional management oversight
// ===========================
if (!assigned &&
    (escalationLevel == 'tier_2' ||
     escalationLevel == 'tier_3' ||
     escalationLevel == 'management')) {
    current.assignment_group.setDisplayValue('Regional Support');
    assigned = true;
}

// ===========================
// RULE 3: Billing & Pricing Complaints → Refund Team
// All financial disputes, overcharges, and billing errors
// ===========================
if (!assigned &&
    (complaintCategory == 'Billing & Pricing' ||
     complaintCategory == 'Overcharge')) {
    current.assignment_group.setDisplayValue('Refund Team');
    assigned = true;
}

// ===========================
// RULE 4: Delivery Complaints → Logistics
// All shipping and delivery-related issues
// ===========================
if (!assigned &&
    (complaintCategory == 'Delivery Issues' ||
     complaintCategory == 'Late Delivery')) {
    current.assignment_group.setDisplayValue('Logistics');
    assigned = true;
}

// ===========================
// RULE 5: Product Quality Routing (by Priority/Severity)
// High priority → Quality Team (investigation)
// Lower priority → Warehouse (inspection/returns)
// ===========================
if (!assigned &&
    (complaintCategory == 'Product Quality' ||
     complaintCategory == 'Defective Product')) {
    if (priority <= 2) {
        current.assignment_group.setDisplayValue('Quality Team');
    } else {
        current.assignment_group.setDisplayValue('Warehouse');
    }
    assigned = true;
}

// ===========================
// RULE 6: Customer Service / Staff Complaints → Store Support
// In-store service issues and staff behavior complaints
// ===========================
if (!assigned &&
    (complaintCategory == 'Customer Service' ||
     complaintCategory == 'Rude Staff')) {
    current.assignment_group.setDisplayValue('Store Support');
    assigned = true;
}

// ===========================
// RULE 7: Physical Store Channel → Store Support
// Any complaint originating from a physical store visit
// ===========================
if (!assigned && channel == 'physical_store') {
    current.assignment_group.setDisplayValue('Store Support');
    assigned = true;
}

// ===========================
// RULE 8: High Priority + Specific Region → Regional Support
// Priority 1-2 cases from specific regions need regional coordination
// ===========================
if (!assigned && priority <= 2 && storeRegion != '') {
    current.assignment_group.setDisplayValue('Regional Support');
    assigned = true;
}

// ===========================
// RULE 9: Food & Beverage Product Issues → Quality Team
// Food safety concerns always go to quality regardless of complaint category
// ===========================
if (!assigned && productDepartment == 'food_beverage') {
    current.assignment_group.setDisplayValue('Quality Team');
    assigned = true;
}

// ===========================
// RULE 10: Default → Customer Care
// Catch-all for cases that don't match specialized routing
// ===========================
if (!assigned) {
    current.assignment_group.setDisplayValue('Customer Care');
}
